import React, { useState } from 'react';
import axios from 'axios';
import { Send, Loader2, AlertCircle, CheckCircle } from 'lucide-react';
import RiskMeter from '../components/RiskMeter';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:8080/api';

const InputForm = () => {
  const [formData, setFormData] = useState({
    loginTime: '',
    failAttempts: '',
    locationChange: '0',
    txnAmount: ''
  });
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    setResult(null);

    try {
      const payload = {
        loginTime: parseInt(formData.loginTime),
        failAttempts: parseInt(formData.failAttempts),
        locationChange: parseInt(formData.locationChange),
        txnAmount: parseFloat(formData.txnAmount)
      };

      const response = await axios.post(`${API_URL}/analyze`, payload);
      setResult(response.data);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to analyze risk. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const resetForm = () => {
    setFormData({
      loginTime: '',
      failAttempts: '',
      locationChange: '0',
      txnAmount: ''
    });
    setResult(null);
    setError('');
  };

  return (
    <div className="container">
      <div className="page-header">
        <h2>Analyze User Behavior</h2>
        <p>Enter user activity data to calculate risk score</p>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: result ? '1fr 1fr' : '1fr', gap: '24px' }}>
        <div className="card">
          <div className="card-header">
            <Send size={22} style={{ color: '#3b82f6' }} />
            <h3>Input Parameters</h3>
          </div>

          <form onSubmit={handleSubmit}>
            <div className="form-row">
              <div className="form-group">
                <label className="form-label">Login Time (Hour 0-23)</label>
                <input
                  type="number"
                  name="loginTime"
                  className="form-input"
                  placeholder="e.g., 14 for 2 PM"
                  min="0"
                  max="23"
                  value={formData.loginTime}
                  onChange={handleChange}
                  required
                />
              </div>

              <div className="form-group">
                <label className="form-label">Failed Login Attempts</label>
                <input
                  type="number"
                  name="failAttempts"
                  className="form-input"
                  placeholder="Number of failed attempts"
                  min="0"
                  max="20"
                  value={formData.failAttempts}
                  onChange={handleChange}
                  required
                />
              </div>
            </div>

            <div className="form-row">
              <div className="form-group">
                <label className="form-label">Location Change</label>
                <select
                  name="locationChange"
                  className="form-input"
                  value={formData.locationChange}
                  onChange={handleChange}
                >
                  <option value="0">No (0)</option>
                  <option value="1">Yes (1)</option>
                </select>
              </div>

              <div className="form-group">
                <label className="form-label">Transaction Amount ($)</label>
                <input
                  type="number"
                  name="txnAmount"
                  className="form-input"
                  placeholder="Transaction amount"
                  min="0"
                  step="0.01"
                  value={formData.txnAmount}
                  onChange={handleChange}
                  required
                />
              </div>
            </div>

            {error && (
              <div className="error-message">
                <AlertCircle size={20} />
                {error}
              </div>
            )}

            <div style={{ display: 'flex', gap: '12px', marginTop: '20px' }}>
              <button type="submit" className="btn btn-primary" disabled={loading}>
                {loading ? <Loader2 size={20} className="spinner-small" /> : <Send size={20} />}
                {loading ? 'Analyzing...' : 'Analyze Risk'}
              </button>
              {result && (
                <button type="button" className="btn btn-secondary" onClick={resetForm}>
                  Reset
                </button>
              )}
            </div>
          </form>
        </div>

        {result && (
          <div className="card">
            <div className="card-header">
              <CheckCircle size={22} style={{ color: '#22c55e' }} />
              <h3>Risk Assessment Result</h3>
            </div>

            <RiskMeter score={result.risk} level={result.level} />

            <div style={{ marginTop: '30px' }}>
              <h4 style={{ marginBottom: '12px', color: '#94a3b8' }}>Input Summary</h4>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                <div style={{ background: 'rgba(15, 23, 42, 0.4)', padding: '12px', borderRadius: '8px' }}>
                  <span style={{ color: '#64748b', fontSize: '0.85rem' }}>Login Time</span>
                  <p style={{ fontWeight: '600', marginTop: '4px' }}>{formData.loginTime}:00</p>
                </div>
                <div style={{ background: 'rgba(15, 23, 42, 0.4)', padding: '12px', borderRadius: '8px' }}>
                  <span style={{ color: '#64748b', fontSize: '0.85rem' }}>Failed Attempts</span>
                  <p style={{ fontWeight: '600', marginTop: '4px' }}>{formData.failAttempts}</p>
                </div>
                <div style={{ background: 'rgba(15, 23, 42, 0.4)', padding: '12px', borderRadius: '8px' }}>
                  <span style={{ color: '#64748b', fontSize: '0.85rem' }}>Location Change</span>
                  <p style={{ fontWeight: '600', marginTop: '4px' }}>{formData.locationChange === '1' ? 'Yes' : 'No'}</p>
                </div>
                <div style={{ background: 'rgba(15, 23, 42, 0.4)', padding: '12px', borderRadius: '8px' }}>
                  <span style={{ color: '#64748b', fontSize: '0.85rem' }}>Transaction</span>
                  <p style={{ fontWeight: '600', marginTop: '4px' }}>${formData.txnAmount}</p>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default InputForm;
